UPDATE words SET example_en_2 = 'The opening scene sets the tone for the whole book.', example_ko_2 = '첫 장면이 책 전체의 분위기를 설정해요.', example_en_3 = 'He read a touching scene from the novel aloud.', example_ko_3 = '그는 소설에서 감동적인 장면을 소리 내어 읽었어요.', example_en_4 = 'My favorite scene is when the two characters finally meet.', example_ko_4 = '제가 가장 좋아하는 장면은 두 등장인물이 드디어 만나는 부분이에요.', example_en_5 = 'Describe the scene you found most memorable.', example_ko_5 = '가장 인상 깊었던 장면을 묘사해보세요.' WHERE id = 'w_humanities_A2_28';

