UPDATE words SET example_en_2 = 'Ancient stories are still told today.', example_ko_2 = '고대 이야기들이 오늘날에도 아직 전해져요.', example_en_3 = 'She is interested in ancient Greek poetry.', example_ko_3 = '그녀는 고대 그리스 시에 관심이 있어요.', example_en_4 = 'The ancient myth of the sun and moon is beautiful.', example_ko_4 = '태양과 달의 고대 신화는 아름다워요.', example_en_5 = 'We can learn a lot from ancient texts.', example_ko_5 = '고대 텍스트에서 많은 것을 배울 수 있어요.' WHERE id = 'w_humanities_A2_32';

UPDATE words SET example_en_2 = 'My grandmother used to tell me folktales at night.', example_ko_2 = '할머니는 밤에 저에게 민담을 들려주곤 했어요.', example_en_3 = 'This folktale teaches children to be honest.', example_ko_3 = '이 민담은 아이들에게 정직하라고 가르쳐요.', example_en_4 = 'Have you read any Japanese folktales?', example_ko_4 = '일본 민담을 읽어본 적 있어요?', example_en_5 = 'Folktales are an important part of a country''s culture.', example_ko_5 = '민담은 나라 문화의 중요한 부분이에요.' WHERE id = 'w_humanities_A2_33';

UPDATE words SET example_en_2 = 'The narrative jumps between past and present.', example_ko_2 = '서사는 과거와 현재를 오가요.', example_en_3 = 'She uses a first-person narrative to tell her story.', example_ko_3 = '그녀는 1인칭 서사를 사용해 이야기를 전달해요.', example_en_4 = 'The narrative of the novel is easy to follow.', example_ko_4 = '소설의 서사는 따라가기 쉬워요.', example_en_5 = 'A strong narrative keeps the reader engaged.', example_ko_5 = '강한 서사는 독자의 관심을 유지시켜요.' WHERE id = 'w_humanities_A2_34';

UPDATE words SET example_en_2 = 'Fantasy is her favorite genre.', example_ko_2 = '판타지는 그녀가 가장 좋아하는 장르예요.', example_en_3 = 'This genre has grown very popular in recent years.', example_ko_3 = '이 장르는 최근 몇 년 동안 매우 인기 있어졌어요.', example_en_4 = 'Which genre do you think is easiest to write?', example_ko_4 = '어떤 장르가 쓰기 가장 쉽다고 생각해요?', example_en_5 = 'The novel is hard to place in one genre.', example_ko_5 = '그 소설은 한 장르에 넣기 어려워요.' WHERE id = 'w_humanities_A2_35';

