UPDATE words SET example_en_2 = 'She used a metaphor to explain her feelings.', example_ko_2 = '그녀는 감정을 설명하기 위해 은유를 사용했어요.', example_en_3 = 'The metaphor of a storm is used to describe his anger.', example_ko_3 = '폭풍의 은유가 그의 분노를 묘사하는 데 사용돼요.', example_en_4 = 'Can you find a metaphor in this poem?', example_ko_4 = '이 시에서 은유를 찾을 수 있어요?', example_en_5 = 'Life is a journey is one of the most common metaphors.', example_ko_5 = '"인생은 여행이다"는 가장 흔한 은유 중 하나예요.' WHERE id = 'w_humanities_B1_01';

UPDATE words SET example_en_2 = 'The theme of family runs through the entire novel.', example_ko_2 = '가족이라는 주제가 소설 전체를 관통해요.', example_en_3 = 'What do you think is the central theme of this poem?', example_ko_3 = '이 시의 중심 주제가 무엇이라고 생각해요?', example_en_4 = 'Freedom and identity are recurring themes in her work.', example_ko_4 = '자유와 정체성은 그녀의 작품에서 반복되는 주제예요.', example_en_5 = 'The theme of loneliness gives the novel its emotional power.', example_ko_5 = '고독의 주제가 소설에 감정적 힘을 부여해요.' WHERE id = 'w_humanities_B1_02';

UPDATE words SET example_en_2 = 'The red rose in the story is rich with symbolism.', example_ko_2 = '이야기 속 빨간 장미는 상징성이 풍부해요.', example_en_3 = 'Symbolism makes the poem more complex and interesting.', example_ko_3 = '상징주의는 시를 더 복잡하고 흥미롭게 만들어요.', example_en_4 = 'She wrote her essay on the symbolism of light and darkness.', example_ko_4 = '그녀는 빛과 어둠의 상징성에 관한 에세이를 썼어요.', example_en_5 = 'Water is often used as symbolism for rebirth.', example_ko_5 = '물은 종종 재탄생의 상징주의로 사용돼요.' WHERE id = 'w_humanities_B1_03';

UPDATE words SET example_en_2 = 'He was asked to analyze the poem for homework.', example_ko_2 = '그는 숙제로 시를 분석하라는 요청을 받았어요.', example_en_3 = 'Let us analyze how the author develops the main character.', example_ko_3 = '작가가 주인공을 어떻게 발전시키는지 분석해봐요.', example_en_4 = 'You need to analyze the text carefully before writing your essay.', example_ko_4 = '에세이를 쓰기 전에 텍스트를 신중하게 분석해야 해요.', example_en_5 = 'She analyzed the use of imagery in three poems.', example_ko_5 = '그녀는 세 편의 시에서 심상 사용을 분석했어요.' WHERE id = 'w_humanities_B1_04';

UPDATE words SET example_en_2 = 'Readers are free to interpret the ending differently.', example_ko_2 = '독자들은 자유롭게 결말을 다르게 해석할 수 있어요.', example_en_3 = 'How did you interpret the silence at the end of the play?', example_ko_3 = '연극 마지막의 침묵을 어떻게 해석했어요?', example_en_4 = 'It is interesting to see how different people interpret the same text.', example_ko_4 = '다양한 사람들이 같은 텍스트를 어떻게 해석하는지 보는 게 흥미로워요.', example_en_5 = 'She interprets the novel through a feminist lens.', example_ko_5 = '그녀는 소설을 페미니즘의 시각으로 해석해요.' WHERE id = 'w_humanities_B1_05';

UPDATE words SET example_en_2 = 'He has a strong interest in literary history.', example_ko_2 = '그는 문학사에 강한 관심이 있어요.', example_en_3 = 'This journal publishes literary essays and reviews.', example_ko_3 = '이 저널은 문학 에세이와 리뷰를 출판해요.', example_en_4 = 'A literary analysis requires close reading of the text.', example_ko_4 = '문학 분석은 텍스트의 꼼꼼한 독해를 필요로 해요.', example_en_5 = 'Her literary taste developed through years of wide reading.', example_ko_5 = '그녀의 문학적 취향은 수년간의 폭넓은 독서를 통해 발전했어요.' WHERE id = 'w_humanities_B1_06';

UPDATE words SET example_en_2 = 'Pride and Prejudice is a classic of English literature.', example_ko_2 = '오만과 편견은 영문학의 고전이에요.', example_en_3 = 'This is considered a classic example of the hero''s journey.', example_ko_3 = '이것은 영웅의 여정의 고전적인 예로 여겨져요.', example_en_4 = 'Why do you think this book is considered a classic?', example_ko_4 = '왜 이 책이 고전으로 여겨진다고 생각해요?', example_en_5 = 'Classic novels often deal with universal human experiences.', example_ko_5 = '고전 소설은 종종 보편적인 인간 경험을 다루어요.' WHERE id = 'w_humanities_B1_07';

UPDATE words SET example_en_2 = 'His critique of the novel was published in a literary journal.', example_ko_2 = '소설에 대한 그의 비평은 문학 저널에 실렸어요.', example_en_3 = 'She wrote a thoughtful critique of the play.', example_ko_3 = '그녀는 연극에 대한 사려 깊은 비평을 썼어요.', example_en_4 = 'A good critique should be fair and evidence-based.', example_ko_4 = '좋은 비평은 공정하고 근거에 기반해야 해요.', example_en_5 = 'The critique raised important questions about the author''s intentions.', example_ko_5 = '그 비평은 작가의 의도에 대한 중요한 질문을 제기했어요.' WHERE id = 'w_humanities_B1_08';

UPDATE words SET example_en_2 = 'Try to see the story from the other character''s perspective.', example_ko_2 = '다른 등장인물의 관점에서 이야기를 보려고 해보세요.', example_en_3 = 'The perspective of the narrator shapes everything we know.', example_ko_3 = '화자의 관점이 우리가 아는 모든 것을 형성해요.', example_en_4 = 'Reading from a different perspective can change your understanding.', example_ko_4 = '다른 관점에서 읽으면 이해가 달라질 수 있어요.', example_en_5 = 'The novel shifts perspective between three different characters.', example_ko_5 = '소설은 세 가지 다른 인물들 사이에서 관점이 전환돼요.' WHERE id = 'w_humanities_B1_09';

UPDATE words SET example_en_2 = 'The contrast between the two characters highlights their differences.', example_ko_2 = '두 인물 간의 대비가 그들의 차이를 부각시켜요.', example_en_3 = 'Notice the contrast between the first and last chapter.', example_ko_3 = '첫 챕터와 마지막 챕터의 대비를 주목해보세요.', example_en_4 = 'She uses contrast between light and dark imagery effectively.', example_ko_4 = '그녀는 빛과 어둠의 심상 대비를 효과적으로 사용해요.', example_en_5 = 'The contrast in tone creates a powerful emotional effect.', example_ko_5 = '어조의 대비가 강력한 감정적 효과를 만들어요.' WHERE id = 'w_humanities_B1_10';

UPDATE words SET example_en_2 = 'The three-act structure is common in Western drama.', example_ko_2 = '3막 구조는 서양 희곡에서 흔해요.', example_en_3 = 'The poem has an unusual structure that reflects its theme.', example_ko_3 = '시는 주제를 반영하는 독특한 구조를 가지고 있어요.', example_en_4 = 'Analyze the structure of the essay before you write your response.', example_ko_4 = '답변을 쓰기 전에 에세이의 구조를 분석해보세요.', example_en_5 = 'The structure of the novel reflects the confusion of the narrator.', example_ko_5 = '소설의 구조는 화자의 혼란을 반영해요.' WHERE id = 'w_humanities_B1_11';

UPDATE words SET example_en_2 = 'The conflict between the characters drives the story forward.', example_ko_2 = '인물들 사이의 갈등이 이야기를 앞으로 이끌어요.', example_en_3 = 'Every good story needs a central conflict to hold the reader.', example_ko_3 = '모든 좋은 이야기는 독자를 붙잡기 위한 중심 갈등이 필요해요.', example_en_4 = 'The internal conflict of the hero makes him more human.', example_ko_4 = '영웅의 내적 갈등이 그를 더 인간적으로 만들어요.', example_en_5 = 'How is the conflict between tradition and change shown in the text?', example_ko_5 = '전통과 변화 사이의 갈등이 텍스트에서 어떻게 나타나나요?' WHERE id = 'w_humanities_B1_12';

UPDATE words SET example_en_2 = 'The narrator describes events from a limited point of view.', example_ko_2 = '화자는 제한된 관점에서 사건을 묘사해요.', example_en_3 = 'Is the narrator the same as the author?', example_ko_3 = '화자와 작가는 같은 사람인가요?', example_en_4 = 'The narrator''s tone becomes sadder as the story progresses.', example_ko_4 = '이야기가 진행되면서 화자의 어조가 점점 슬퍼져요.', example_en_5 = 'A first-person narrator can only tell us what they see and feel.', example_ko_5 = '1인칭 화자는 자신이 보고 느끼는 것만 이야기할 수 있어요.' WHERE id = 'w_humanities_B1_13';

UPDATE words SET example_en_2 = 'The tone of the letter changes dramatically in the last paragraph.', example_ko_2 = '편지의 어조가 마지막 단락에서 극적으로 바뀌어요.', example_en_3 = 'What is the overall tone of the poem?', example_ko_3 = '시의 전반적인 어조는 무엇인가요?', example_en_4 = 'The author''s tone suggests she is critical of the society she describes.', example_ko_4 = '작가의 어조는 그녀가 묘사하는 사회를 비판적으로 본다는 걸 나타내요.', example_en_5 = 'A hopeful tone at the end balances the darker earlier chapters.', example_ko_5 = '끝의 희망적인 어조가 앞부분의 더 어두운 챕터들과 균형을 이뤄요.' WHERE id = 'w_humanities_B1_14';

UPDATE words SET example_en_2 = 'The poem''s imagery of rain suggests sadness.', example_ko_2 = '시의 비 심상은 슬픔을 암시해요.', example_en_3 = 'List the examples of nature imagery in this poem.', example_ko_3 = '이 시에서 자연 심상의 예시를 나열해보세요.', example_en_4 = 'Strong imagery makes the reader feel as if they are there.', example_ko_4 = '강한 심상은 독자가 그곳에 있는 것처럼 느끼게 해요.', example_en_5 = 'She uses sensory imagery to bring the setting alive.', example_ko_5 = '그녀는 배경을 생생하게 살리기 위해 감각적 심상을 사용해요.' WHERE id = 'w_humanities_B1_15';

UPDATE words SET example_en_2 = 'The influence of Shakespeare on English literature is enormous.', example_ko_2 = '영문학에 미친 셰익스피어의 영향은 엄청나요.', example_en_3 = 'Which author has had the greatest influence on your writing?', example_ko_3 = '어떤 작가가 당신의 글쓰기에 가장 큰 영향을 미쳤나요?', example_en_4 = 'Greek mythology still has a strong influence on modern literature.', example_ko_4 = '그리스 신화는 아직도 현대 문학에 강한 영향을 미쳐요.', example_en_5 = 'Her experience abroad had a lasting influence on her writing style.', example_ko_5 = '해외 경험이 그녀의 글쓰기 스타일에 지속적인 영향을 미쳤어요.' WHERE id = 'w_humanities_B1_16';

UPDATE words SET example_en_2 = 'Consider the social context when you analyze the poem.', example_ko_2 = '시를 분석할 때 사회적 맥락을 고려해보세요.', example_en_3 = 'Without knowing the context, the meaning is unclear.', example_ko_3 = '맥락을 모르면 의미가 불명확해요.', example_en_4 = 'The novel must be read in its historical context.', example_ko_4 = '소설은 역사적 맥락 속에서 읽어야 해요.', example_en_5 = 'Context helps us understand why a character makes certain choices.', example_ko_5 = '맥락은 왜 등장인물이 특정 선택을 하는지 이해하는 데 도움이 돼요.' WHERE id = 'w_humanities_B1_17';

UPDATE words SET example_en_2 = 'The broken clock is a symbol of time standing still.', example_ko_2 = '부서진 시계는 시간이 멈춘 것의 상징이에요.', example_en_3 = 'What symbol does the author use to represent hope?', example_ko_3 = '작가는 희망을 나타내기 위해 어떤 상징을 사용하나요?', example_en_4 = 'The ship is used as a symbol of freedom in the novel.', example_ko_4 = '배는 소설에서 자유의 상징으로 사용돼요.', example_en_5 = 'Identify and explain one symbol from the poem.', example_ko_5 = '시에서 하나의 상징을 찾아 설명해보세요.' WHERE id = 'w_humanities_B1_18';

UPDATE words SET example_en_2 = 'I read a biography of Virginia Woolf last summer.', example_ko_2 = '지난 여름 버지니아 울프 전기를 읽었어요.', example_en_3 = 'The biography reveals many unknown facts about the author.', example_ko_3 = '전기는 작가에 대한 많은 알려지지 않은 사실들을 밝혀요.', example_en_4 = 'Would you prefer to read a biography or an autobiography?', example_ko_4 = '전기와 자서전 중 어떤 걸 읽는 걸 선호해요?', example_en_5 = 'The biography helped me understand the themes in her novels.', example_ko_5 = '전기는 그녀의 소설의 주제를 이해하는 데 도움이 됐어요.' WHERE id = 'w_humanities_B1_19';

UPDATE words SET example_en_2 = 'This novel belongs to the realist tradition in literature.', example_ko_2 = '이 소설은 문학의 사실주의 전통에 속해요.', example_en_3 = 'She studied the oral tradition of storytelling in Africa.', example_ko_3 = '그녀는 아프리카의 구전 이야기 전통을 연구했어요.', example_en_4 = 'The novel challenges the tradition of the happy ending.', example_ko_4 = '그 소설은 해피엔딩의 전통에 도전해요.', example_en_5 = 'Understanding a literary tradition helps you see how authors innovate.', example_ko_5 = '문학 전통을 이해하면 작가들이 어떻게 혁신하는지 볼 수 있어요.' WHERE id = 'w_humanities_B1_20';

UPDATE words SET example_en_2 = 'Greek tragedy often ends with the death of the hero.', example_ko_2 = '그리스 비극은 종종 영웅의 죽음으로 끝나요.', example_en_3 = 'Oedipus Rex is considered the greatest ancient tragedy.', example_ko_3 = '오이디푸스 왕은 가장 위대한 고대 비극으로 여겨져요.', example_en_4 = 'The tragedy of the novel lies in the hero''s missed opportunities.', example_ko_4 = '소설의 비극은 영웅이 놓친 기회에 있어요.', example_en_5 = 'She specializes in the study of Shakespearean tragedy.', example_ko_5 = '그녀는 셰익스피어 비극 연구를 전문으로 해요.' WHERE id = 'w_humanities_B1_21';

UPDATE words SET example_en_2 = 'The play is a comedy but it raises serious questions.', example_ko_2 = '그 연극은 희극이지만 진지한 질문을 제기해요.', example_en_3 = 'In classical comedy, all conflicts are resolved happily.', example_ko_3 = '고전 희극에서는 모든 갈등이 행복하게 해결돼요.', example_en_4 = 'She prefers romantic comedy to darker genres.', example_ko_4 = '그녀는 더 어두운 장르보다 로맨틱 코미디를 선호해요.', example_en_5 = 'The comedy relies on misunderstandings between characters.', example_ko_5 = '그 희극은 등장인물들 사이의 오해에 의존해요.' WHERE id = 'w_humanities_B1_22';

UPDATE words SET example_en_2 = 'Each verse of the song tells a different part of the story.', example_ko_2 = '노래의 각 절이 이야기의 다른 부분을 이야기해요.', example_en_3 = 'The poet uses short verses to create a quick rhythm.', example_ko_3 = '시인은 빠른 리듬을 만들기 위해 짧은 절을 사용해요.', example_en_4 = 'She memorized the first verse of the poem for class.', example_ko_4 = '그녀는 수업을 위해 시의 첫 절을 암기했어요.', example_en_5 = 'Try writing a poem in four-line verses.', example_ko_5 = '4행 절로 시를 써보세요.' WHERE id = 'w_humanities_B1_23';

UPDATE words SET example_en_2 = 'He writes in a very clear and simple prose style.', example_ko_2 = '그는 매우 명확하고 단순한 산문 스타일로 써요.', example_en_3 = 'The prose of her novels is elegant and precise.', example_ko_3 = '그녀의 소설의 산문은 우아하고 정확해요.', example_en_4 = 'What is the difference between prose and poetry?', example_ko_4 = '산문과 시의 차이는 무엇인가요?', example_en_5 = 'His prose reads almost like music.', example_ko_5 = '그의 산문은 거의 음악처럼 읽혀요.' WHERE id = 'w_humanities_B1_24';

UPDATE words SET example_en_2 = 'She made a reference to Shakespeare in her essay.', example_ko_2 = '그녀는 에세이에서 셰익스피어를 언급했어요.', example_en_3 = 'Always include references to the text when making a claim.', example_ko_3 = '주장할 때 항상 텍스트 인용을 포함해주세요.', example_en_4 = 'The novel is full of references to ancient mythology.', example_ko_4 = '소설은 고대 신화에 대한 언급으로 가득해요.', example_en_5 = 'His poetry makes reference to the lives of ordinary workers.', example_ko_5 = '그의 시는 평범한 노동자들의 삶을 언급해요.' WHERE id = 'w_humanities_B1_25';

UPDATE words SET example_en_2 = 'She opened her speech with a quotation from a famous poet.', example_ko_2 = '그녀는 유명한 시인의 인용문으로 연설을 시작했어요.', example_en_3 = 'Always put quotation marks around direct quotes.', example_ko_3 = '직접 인용구 주변에는 항상 인용 부호를 붙여주세요.', example_en_4 = 'Can you find a quotation from the text to support your argument?', example_ko_4 = '주장을 뒷받침하기 위한 인용문을 텍스트에서 찾을 수 있어요?', example_en_5 = 'The quotation at the start of the chapter sets the tone perfectly.', example_ko_5 = '챕터 시작의 인용문이 어조를 완벽하게 설정해요.' WHERE id = 'w_humanities_B1_26';

UPDATE words SET example_en_2 = 'She wrote a personal essay about her experience learning English.', example_ko_2 = '그녀는 영어를 배운 경험에 대한 개인 에세이를 썼어요.', example_en_3 = 'His essay on modernism is required reading for the course.', example_ko_3 = '모더니즘에 대한 그의 에세이는 이 과목의 필수 읽기예요.', example_en_4 = 'Write an essay comparing two poems by the same author.', example_ko_4 = '같은 작가의 두 시를 비교하는 에세이를 써보세요.', example_en_5 = 'The essay argues that the novel is a political text.', example_ko_5 = '그 에세이는 소설이 정치적 텍스트라고 주장해요.' WHERE id = 'w_humanities_B1_27';

UPDATE words SET example_en_2 = 'Readers responded with great enthusiasm to the new novel.', example_ko_2 = '독자들은 새 소설에 큰 열정으로 반응했어요.', example_en_3 = 'How did the audience respond to the play''s tragic ending?', example_ko_3 = '관객들은 연극의 비극적 결말에 어떻게 반응했나요?', example_en_4 = 'She responded to the critique with a thoughtful rebuttal.', example_ko_4 = '그녀는 비평에 사려 깊은 반박으로 응했어요.', example_en_5 = 'I would like you to respond to the argument in the essay.', example_ko_5 = '에세이의 주장에 응해주셨으면 해요.' WHERE id = 'w_humanities_B1_28';

UPDATE words SET example_en_2 = 'The novel explores what it means to belong somewhere.', example_ko_2 = '소설은 어딘가에 속한다는 것이 무엇을 의미하는지 탐구해요.', example_en_3 = 'She wrote a poem to explore her feelings about home.', example_ko_3 = '그녀는 고향에 대한 감정을 탐구하기 위해 시를 썼어요.', example_en_4 = 'This essay explores the theme of guilt in three novels.', example_ko_4 = '이 에세이는 세 편의 소설에서 죄책감의 주제를 탐구해요.', example_en_5 = 'Good literature invites us to explore difficult questions.', example_ko_5 = '좋은 문학은 우리를 어려운 질문들을 탐구하도록 초대해요.' WHERE id = 'w_humanities_B1_29';

UPDATE words SET example_en_2 = 'The festival aims to promote cultural exchange through literature.', example_ko_2 = '그 축제는 문학을 통한 문화 교류를 증진하는 것을 목표로 해요.', example_en_3 = 'Understanding cultural differences makes us better readers.', example_ko_3 = '문화적 차이를 이해하면 더 나은 독자가 될 수 있어요.', example_en_4 = 'The novel has great cultural importance in Korea.', example_ko_4 = '그 소설은 한국에서 큰 문화적 중요성을 지녀요.', example_en_5 = 'She wrote about the cultural impact of Korean folktales.', example_ko_5 = '그녀는 한국 민담의 문화적 영향에 대해 썼어요.' WHERE id = 'w_humanities_B1_30';

UPDATE words SET example_en_2 = 'The last page of the novel reveals who the real villain is.', example_ko_2 = '소설의 마지막 페이지에서 진짜 악당이 누구인지 밝혀져요.', example_en_3 = 'The poem gradually reveals the speaker''s grief.', example_ko_3 = '시는 점차 화자의 슬픔을 드러내요.', example_en_4 = 'What does the final scene reveal about the hero''s character?', example_ko_4 = '마지막 장면은 영웅의 성격에 대해 무엇을 드러내나요?', example_en_5 = 'The dialogue reveals a hidden tension between the two characters.', example_ko_5 = '대화는 두 인물 사이의 숨겨진 긴장감을 드러내요.' WHERE id = 'w_humanities_B1_31';

UPDATE words SET example_en_2 = 'This book appeals to a wide audience of all ages.', example_ko_2 = '이 책은 모든 연령의 넓은 독자층에게 어필해요.', example_en_3 = 'The author had a clear sense of her intended audience.', example_ko_3 = '작가는 의도한 독자에 대해 명확한 감각이 있었어요.', example_en_4 = 'Online publishing has helped authors reach a global audience.', example_ko_4 = '온라인 출판은 작가들이 세계적인 독자층에 도달하는 데 도움이 됐어요.', example_en_5 = 'Consider your audience before choosing the tone of your essay.', example_ko_5 = '에세이의 어조를 선택하기 전에 독자를 고려해보세요.' WHERE id = 'w_humanities_B1_32';

UPDATE words SET example_en_2 = 'This passage from the novel is often used in literature exams.', example_ko_2 = '소설의 이 구절은 종종 문학 시험에 사용돼요.', example_en_3 = 'Read the passage carefully before answering the questions.', example_ko_3 = '질문에 답하기 전에 구절을 주의 깊게 읽어보세요.', example_en_4 = 'She chose a passage that best showed the author''s style.', example_ko_4 = '그녀는 작가의 스타일을 가장 잘 보여주는 구절을 골랐어요.', example_en_5 = 'The passage is remarkable for its beautiful use of imagery.', example_ko_5 = '그 구절은 심상의 아름다운 사용으로 주목할 만해요.' WHERE id = 'w_humanities_B1_33';

UPDATE words SET example_en_2 = 'The author uses an anecdote to illustrate her main point.', example_ko_2 = '작가는 요점을 설명하기 위해 일화를 사용해요.', example_en_3 = 'Can you illustrate the theme with an example from the text?', example_ko_3 = '텍스트의 예시로 주제를 설명해줄 수 있어요?', example_en_4 = 'The teacher illustrated the idea of symbolism with three examples.', example_ko_4 = '선생님은 세 가지 예시로 상징주의 개념을 설명했어요.', example_en_5 = 'A good essay should illustrate each point with evidence.', example_ko_5 = '좋은 에세이는 각 요점을 근거로 설명해야 해요.' WHERE id = 'w_humanities_B1_34';

UPDATE words SET example_en_2 = 'The novel had a huge impact on how people view mental illness.', example_ko_2 = '소설은 사람들이 정신 질환을 바라보는 방식에 큰 영향을 미쳤어요.', example_en_3 = 'What impact do you think this poem has had on readers?', example_ko_3 = '이 시가 독자들에게 어떤 영향을 미쳤다고 생각해요?', example_en_4 = 'The emotional impact of the ending stayed with me for days.', example_ko_4 = '결말의 감정적 영향이 며칠 동안 저와 함께했어요.', example_en_5 = 'Literature has the power to create a lasting social impact.', example_ko_5 = '문학은 지속적인 사회적 영향을 만드는 힘이 있어요.' WHERE id = 'w_humanities_B1_35';

